const input = $input.first().json;
const query = input.query || {};
const { search, estado, categoria, limit = 50, offset = 0 } = query;

const searchPattern = search ? `%${search}%` : '%';
const allowedEstados = ['NUEVO', 'FRIO', 'TIBIO', 'CALIENTE', 'ACTIVO', 'PAUSADO', 'BAJA'];
const estadoFilter = estado && allowedEstados.includes(estado) ? `estado = '${estado}'` : `estado IN ('NUEVO','FRIO','TIBIO','CALIENTE','ACTIVO','PAUSADO','BAJA')`;
const allowedCategorias = ['KIDS', 'AU_PAIR', 'ADULTOS', 'PERSONALIZADO', 'KIDS-ADOLESCENTES'];
const categoriaFilter = categoria && allowedCategorias.includes(categoria) ? `categoria = '${categoria}'` : 'true';

const queryList = `SELECT id, nombre, whatsapp, email, estado, categoria, 
       horario_clase, foto_url, fecha_registro, ultimo_contacto
FROM alumnos
WHERE (nombre ILIKE '${searchPattern}' OR whatsapp ILIKE '${searchPattern}' OR email ILIKE '${searchPattern}')
AND (${estadoFilter})
AND (${categoriaFilter})
ORDER BY fecha_registro DESC
LIMIT ${parseInt(limit)} OFFSET ${parseInt(offset)};`;

const queryCount = `SELECT COUNT(*) as total
FROM alumnos
WHERE (nombre ILIKE '${searchPattern}' OR whatsapp ILIKE '${searchPattern}' OR email ILIKE '${searchPattern}')
AND (${estadoFilter})
AND (${categoriaFilter});`;

return [{
  json: {
    queryList,
    queryCount,
    limit,
    offset
  }
}];

const items = $('Select Alumnos').all().map(row => row.json);
const totalData = $('Count Total').first().json;
const total = totalData.total;
const limit = $input.first().json.limit;
const offset = $input.first().json.offset;

return [{
  json: {
    items,
    total,
    limit,
    offset
  }
}];

